import React, {useState} from "react";
import CssCanvas from "./CssCanvas.jsx";

function CssMenu() {
    // const [displayTypeState, setDisplayType] = useState("flex");
    

    return (
        <div className="CssPlayspace">
            <div className="CssMenu">
                <form>
                    <label for="input1">display: </label>
                    <select name="input1" onChange={(e) => e.target.value}>
                        <option value={setDisplayType("flex")}>flex</option>
                        <option value={setDisplayType("block")}>block</option>
                        <option value={setDisplayType("grid")}>grid</option>
                        <option value={setDisplayType("none")}>none</option>
                    </select>
                </form>
            </div>
            <CssCanvas displayType={displayTypeState}/>
        </div>
    )
} 

export default CssMenu;
